parameters.jsCode:
// 1. Get the data from the input
const input = $input.first().json;

// 2. Transform the mapping into "Header: Column" format
const mappingEntries = Object.entries(input.column_mapping || {});

// Sort alphabetically by the Original Header (the Key) for easy lookups
mappingEntries.sort((a, b) => a[0].localeCompare(b[0]));

// 3. Format as: "Account Name: string3<br>"
// This ensures each entry is on its own line when viewed in a web context
const humanReadableMapping = mappingEntries
    .map(([header, dbCol]) => `${header}: ${dbCol}<br>`)
    .join('');

// 4. Return the data with all original fields preserved
return {
    ...input,
    readable_mapping: humanReadableMapping
};

